import torch_pruning as tp
from collections import defaultdict

EPS = torch.finfo(torch.float32).eps

def _find_norm_linear_pairs(model, example_input):
    "Use torch-pruning dependency graph to find (Norm → [Linear...]) groups"
    DG = tp.DependencyGraph()
    DG.build_dependency(model, example_inputs=example_input)

    def _find_preceding_norm(node, visited=None):
        if visited is None: visited = set()
        if id(node) in visited: return None
        visited.add(id(node))
        m = getattr(node, 'module', None)
        if isinstance(m, (nn.LayerNorm, nn.BatchNorm1d, nn.BatchNorm2d)):
            return m
        for inp in node.inputs:
            result = _find_preceding_norm(inp, visited)
            if result is not None: return result
        return None

    groups = defaultdict(list)
    for m, node in DG.module2node.items():
        if isinstance(m, nn.Linear) and hasattr(m, 'weight'):
            norm = _find_preceding_norm(node)
            if norm is not None and hasattr(norm, 'normalized_shape'):
                if m.in_features == norm.normalized_shape[0]:
                    groups[norm].append(m)
    return dict(groups)

def _collect_channel_max(model, data, modules, n_batches=5):
    "Collect per-channel max absolute activation values for specific modules"
    device = next(model.parameters()).device
    scales, hooks = {}, []

    for m in modules:
        ch = m.in_features if isinstance(m, nn.Linear) else m.weight.shape[1]
        scales[m] = torch.zeros(ch, device=device)
        def make_hook(module):
            def hook(mod, inp):
                x = inp[0].detach().abs()
                dims = [i for i in range(x.dim()) if i != (x.dim()-1 if isinstance(module, nn.Linear) else 1)]
                scales[module] = torch.max(scales[module], x.amax(dim=dims))
            return hook
        hooks.append(m.register_forward_pre_hook(make_hook(m)))

    model.eval()
    with torch.no_grad():
        if isinstance(data, torch.Tensor):
            model(data.to(device))
        else:
            for n, batch in enumerate(data):
                if n >= n_batches: break
                xb = batch[0] if isinstance(batch, (tuple, list)) else batch
                model(xb.as_subclass(torch.Tensor).to(device))

    for h in hooks: h.remove()
    return scales

def compute_smooth_scales(act_scales, weight_scales, alpha=0.5):
    "Compute per-channel SmoothQuant scales: s = act^alpha / weight^(1-alpha)"
    return (act_scales + EPS).pow(alpha) / (weight_scales + EPS).pow(1 - alpha)

def smooth_quant(model: nn.Module,         # Model to smooth (returns a deepcopy)
                 data,                     # Calibration data (tensor, list, or DataLoader)
                 alpha: float = 0.5,       # Migration strength (0=no effect, 1=full migration)
                 n_batches: int = 5,       # Calibration batches
) -> nn.Module:
    "Apply SmoothQuant: migrate activation outliers to weights via Norm÷s, Linear×s pairs"
    if not (0 <= alpha <= 1):
        raise ValueError(f"alpha must be in [0, 1], got {alpha}")

    model = copy.deepcopy(model)

    # Get example input for graph tracing
    if isinstance(data, torch.Tensor): example = data[:1]
    else:
        batch = next(iter(data))
        example = (batch[0] if isinstance(batch, (tuple, list)) else batch)[:1]
        example = example.as_subclass(torch.Tensor)

    # Find (Norm → [Linear...]) pairs via dependency graph
    pairs = _find_norm_linear_pairs(model, example.to(next(model.parameters()).device))
    if not pairs: return model

    # Collect activation scales for all target linears
    all_linears = [lin for lins in pairs.values() for lin in lins]
    act_scales = _collect_channel_max(model, data, all_linears, n_batches)

    # Apply smoothing per group
    for norm, linears in pairs.items():
        # Weight scales = max across all linears in the group
        weight_scales = torch.stack([lin.weight.abs().amax(dim=0) for lin in linears]).amax(dim=0)
        # Activation scales = max across all linears in the group (should be same, but be safe)
        group_act = torch.stack([act_scales[lin] for lin in linears]).amax(dim=0)

        s = compute_smooth_scales(group_act, weight_scales, alpha)

        # Norm side: divide weight and bias by s
        norm.weight.data.div_(s)
        if norm.bias is not None:
            norm.bias.data.div_(s)

        # Linear side: multiply weights by s
        for lin in linears:
            lin.weight.data = torch.einsum('oi, i -> oi', lin.weight.data, s)

    return model
